diff:
diff --git a/binder.go b/binder.go
index 32029ec..0342c89 100644
--- a/binder.go
+++ b/binder.go
@@ -72,6 +72,8 @@ type BindingError struct {
 	*HTTPError
 	// Values of parameter that failed to bind.
 	Values []string `json:"-"`
+	// ExpectedType is the Go type name that the value was being converted to.
+	ExpectedType string `json:"expectedType,omitempty"`
 }

 // NewBindingError creates new instance of binding error
@@ -182,6 +184,14 @@ func (b *ValueBinder) setError(err error) {
 	b.errors = append(b.errors, err)
 }

+// setTypedError records a binding error and sets ExpectedType on the error if it is a *BindingError.
+func (b *ValueBinder) setTypedError(err error, expectedType string) {
+	b.setError(err)
+	if be, ok := err.(*BindingError); ok {
+		be.ExpectedType = expectedType
+	}
+}
+
 // BindError returns first seen bind error and resets/empties binder errors for further calls
 func (b *ValueBinder) BindError() error {
 	if b.errors == nil {
@@ -515,10 +525,13 @@ func (b *ValueBinder) intValue(sourceParam string, dest any, bitSize int, valueM
 func (b *ValueBinder) int(sourceParam string, value string, dest any, bitSize int) *ValueBinder {
 	n, err := strconv.ParseInt(value, 10, bitSize)
 	if err != nil {
+		var typeName string
 		if bitSize == 0 {
-			b.setError(b.ErrorFunc(sourceParam, []string{value}, "failed to bind field value to int", err))
+			typeName = "int"
+			b.setTypedError(b.ErrorFunc(sourceParam, []string{value}, "failed to bind field value to int", err), typeName)
 		} else {
-			b.setError(b.ErrorFunc(sourceParam, []string{value}, fmt.Sprintf("failed to bind field value to int%v", bitSize), err))
+			typeName = fmt.Sprintf("int%v", bitSize)
+			b.setTypedError(b.ErrorFunc(sourceParam, []string{value}, fmt.Sprintf("failed to bind field value to int%v", bitSize), err), typeName)
 		}
 		return b
 	}
@@ -744,9 +757,9 @@ func (b *ValueBinder) uint(sourceParam string, value string, dest any, bitSize i
 	n, err := strconv.ParseUint(value, 10, bitSize)
 	if err != nil {
 		if bitSize == 0 {
-			b.setError(b.ErrorFunc(sourceParam, []string{value}, "failed to bind field value to uint", err))
+			b.setTypedError(b.ErrorFunc(sourceParam, []string{value}, "failed to bind field value to uint", err), "uint")
 		} else {
-			b.setError(b.ErrorFunc(sourceParam, []string{value}, fmt.Sprintf("failed to bind field value to uint%v", bitSize), err))
+			b.setTypedError(b.ErrorFunc(sourceParam, []string{value}, fmt.Sprintf("failed to bind field value to uint%v", bitSize), err), fmt.Sprintf("uint%v", bitSize))
 		}
 		return b
 	}
@@ -920,7 +933,7 @@ func (b *ValueBinder) boolValue(sourceParam string, dest *bool, valueMustExist b
