 	n, err := strconv.ParseBool(value)
 	if err != nil {
-		b.setError(b.ErrorFunc(sourceParam, []string{value}, "failed to bind field value to bool", err))
+		b.setTypedError(b.ErrorFunc(sourceParam, []string{value}, "failed to bind field value to bool", err), "bool")
 		return b
 	}

@@ -1006,7 +1019,7 @@ func (b *ValueBinder) floatValue(sourceParam string, dest any, bitSize int, valu
 func (b *ValueBinder) float(sourceParam string, value string, dest any, bitSize int) *ValueBinder {
 	n, err := strconv.ParseFloat(value, bitSize)
 	if err != nil {
-		b.setError(b.ErrorFunc(sourceParam, []string{value}, fmt.Sprintf("failed to bind field value to float%v", bitSize), err))
+		b.setTypedError(b.ErrorFunc(sourceParam, []string{value}, fmt.Sprintf("failed to bind field value to float%v", bitSize), err), fmt.Sprintf("float%v", bitSize))
 		return b
 	}
